-- ===================================================================
-- 1. 테이블 생성 (Schema Definition)
-- ===================================================================

-- 교과목 기초 정보 테이블
CREATE TABLE IF NOT EXISTS courses (
                                       id BIGINT PRIMARY KEY,                -- 제공된 과목 고유 ID (101번부터 직접 지정)
                                       course_code VARCHAR(50) NOT NULL,     -- 과목 코드 (예: 'CS101')
    title VARCHAR(255) NOT NULL,          -- 과목명 (API 검색 및 조회 대상)
    credits INT NOT NULL,                 -- 학점
    grade_level INT NOT NULL,             -- 학년 (1, 2, 3, 4)
    semester INT NOT NULL,                -- 학기 (1, 2)
    category VARCHAR(100) NOT NULL,       -- 이수구분 (공통, SW전공, 컴공전공 등)
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
    );

-- 과목 별 선수관계 정보 테이블
CREATE TABLE IF NOT EXISTS prerequisites (
                                             id BIGINT AUTO_INCREMENT PRIMARY KEY,
                                             pre_course_id BIGINT NOT NULL,        -- 선수 과목 ID (먼저 들어야 하는 과목)
                                             post_course_id BIGINT NOT NULL,       -- 후수 과목 ID (나중에 듣는 과목)
                                             FOREIGN KEY (pre_course_id) REFERENCES courses(id) ON DELETE CASCADE,
    FOREIGN KEY (post_course_id) REFERENCES courses(id) ON DELETE CASCADE
    );

